import{f as d,D as E,o as s,c as A,a2 as r,b as l,w as a,a as e,G as o,a5 as i}from"./chunks/framework.DHYrF-q6.js";const f=JSON.parse('{"title":"服务拆分方法论","description":"","frontmatter":{},"headers":[],"relativePath":"spring-ecosystem/microservice-methodology/service-split.md","filePath":"spring-ecosystem/microservice-methodology/service-split.md","lastUpdated":1780925101000}'),p={name:"spring-ecosystem/microservice-methodology/service-split.md"};function c(h,t,b,B,g,u){const n=E("Mermaid");return s(),A("div",null,[t[3]||(t[3]=r('<h1 id="服务拆分方法论" tabindex="-1">服务拆分方法论 <a class="header-anchor" href="#服务拆分方法论" aria-label="Permalink to &quot;服务拆分方法论&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识模块</th><th>重点内容</th><th>面试频率</th></tr></thead><tbody><tr><td>拆分原则</td><td>单一职责、高内聚低耦合、数据主权、独立部署</td><td>极高</td></tr><tr><td>DDD 限界上下文</td><td>战略设计核心，子域划分（核心域/支撑域/通用域）</td><td>极高</td></tr><tr><td>拆分维度</td><td>按业务能力、按组织结构、按变化频率三种维度对比</td><td>高</td></tr><tr><td>服务粒度判断</td><td>太小（纳米服务问题）vs 太大（迷你单体问题）的平衡</td><td>极高</td></tr><tr><td>反模式</td><td>按数据库表拆分、按技术层拆分、过早拆分、过度拆分</td><td>高</td></tr><tr><td>绞杀者模式</td><td>渐进式拆分，逐步替代，而非大爆炸重写</td><td>中高</td></tr></tbody></table><hr><h2 id="一、服务拆分的核心原则" tabindex="-1">一、服务拆分的核心原则 <a class="header-anchor" href="#一、服务拆分的核心原则" aria-label="Permalink to &quot;一、服务拆分的核心原则&quot;">​</a></h2><h3 id="_1-1-五大黄金原则" tabindex="-1">1.1 五大黄金原则 <a class="header-anchor" href="#_1-1-五大黄金原则" aria-label="Permalink to &quot;1.1 五大黄金原则&quot;">​</a></h3>',6)),(s(),l(i,null,{default:a(()=>[o(n,{id:"mermaid-96",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20CENTER%5B%E6%9C%8D%E5%8A%A1%E6%8B%86%E5%88%86%3Cbr%2F%3E%E4%BA%94%E5%A4%A7%E5%8E%9F%E5%88%99%5D%0A%0A%20%20%20%20CENTER%20--%3E%20P1%5B%E5%8D%95%E4%B8%80%E8%81%8C%E8%B4%A3%3Cbr%2F%3E%E4%B8%80%E4%B8%AA%E6%9C%8D%E5%8A%A1%E5%8F%AA%E5%81%9A%E4%B8%80%E4%BB%B6%E4%BA%8B%5D%0A%20%20%20%20CENTER%20--%3E%20P2%5B%E9%AB%98%E5%86%85%E8%81%9A%E4%BD%8E%E8%80%A6%E5%90%88%3Cbr%2F%3E%E5%86%85%E9%83%A8%E9%AB%98%E5%BA%A6%E5%85%B3%E8%81%94%EF%BC%8C%E5%A4%96%E9%83%A8%E6%9C%80%E5%B0%8F%E4%BE%9D%E8%B5%96%5D%0A%20%20%20%20CENTER%20--%3E%20P3%5B%E6%95%B0%E6%8D%AE%E4%B8%BB%E6%9D%83%3Cbr%2F%3E%E6%AF%8F%E4%B8%AA%E6%9C%8D%E5%8A%A1%E6%8B%A5%E6%9C%89%E8%87%AA%E5%B7%B1%E7%9A%84%E6%95%B0%E6%8D%AE%E5%BA%93%5D%0A%20%20%20%20CENTER%20--%3E%20P4%5B%E7%8B%AC%E7%AB%8B%E9%83%A8%E7%BD%B2%3Cbr%2F%3E%E5%8F%AF%E7%8B%AC%E7%AB%8B%E6%9E%84%E5%BB%BA%E3%80%81%E6%B5%8B%E8%AF%95%E3%80%81%E5%8F%91%E5%B8%83%5D%0A%20%20%20%20CENTER%20--%3E%20P5%5B%E5%9B%B4%E7%BB%95%E4%B8%9A%E5%8A%A1%3Cbr%2F%3E%E6%8C%89%E4%B8%9A%E5%8A%A1%E8%83%BD%E5%8A%9B%E8%80%8C%E9%9D%9E%E6%8A%80%E6%9C%AF%E5%B1%82%E6%8B%86%E5%88%86%5D%0A%0A%20%20%20%20style%20CENTER%20fill%3A%234d96ff%2Ccolor%3A%23fff%0A%20%20%20%20style%20P1%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20P2%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20P3%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20P4%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20P5%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[e(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r('<div class="danger custom-block"><p class="custom-block-title">拆分第一准则：数据是硬边界</p><p>服务拆分最核心的原则就是<strong>数据隔离</strong>。如果两个&quot;服务&quot;共享同一个数据库，它们本质上还是一个分布式单体。数据库是服务之间最硬的边界——跨服务的数据访问必须通过 API 调用，绝不能直接连对方的数据库。</p></div><h3 id="_1-2-拆分前必须回答的三个问题" tabindex="-1">1.2 拆分前必须回答的三个问题 <a class="header-anchor" href="#_1-2-拆分前必须回答的三个问题" aria-label="Permalink to &quot;1.2 拆分前必须回答的三个问题&quot;">​</a></h3><ol><li><strong>这个模块是否可以独立交付业务价值？</strong> 如果不能，它可能不是一个独立服务</li><li><strong>这个模块的变化是否独立于其他模块？</strong> 如果每次改动都需要其他模块配合上线，边界可能画错了</li><li><strong>这个模块是否有独立的数据存储？</strong> 没有独立数据的&quot;服务&quot;只是部署单元，不是微服务</li></ol><hr><h2 id="二、ddd-限界上下文与微服务拆分" tabindex="-1">二、DDD 限界上下文与微服务拆分 <a class="header-anchor" href="#二、ddd-限界上下文与微服务拆分" aria-label="Permalink to &quot;二、DDD 限界上下文与微服务拆分&quot;">​</a></h2><h3 id="_2-1-ddd-战略设计核心概念" tabindex="-1">2.1 DDD 战略设计核心概念 <a class="header-anchor" href="#_2-1-ddd-战略设计核心概念" aria-label="Permalink to &quot;2.1 DDD 战略设计核心概念&quot;">​</a></h3><p>DDD（Domain-Driven Design）的战略设计为微服务拆分提供了系统化的方法论。核心概念映射关系：</p><table tabindex="0"><thead><tr><th>DDD 概念</th><th>微服务对应</th><th>说明</th></tr></thead><tbody><tr><td><strong>限界上下文</strong>（Bounded Context）</td><td>微服务边界</td><td>一个限界上下文对应一个或一组微服务</td></tr><tr><td><strong>子域</strong>（Subdomain）</td><td>业务模块</td><td>核心域、支撑域、通用域</td></tr><tr><td><strong>上下文映射</strong>（Context Map）</td><td>服务间集成关系</td><td>上下游、防腐层、共享内核等</td></tr><tr><td><strong>聚合</strong>（Aggregate）</td><td>事务边界</td><td>一个聚合内保证强一致性</td></tr><tr><td><strong>领域事件</strong>（Domain Event）</td><td>异步消息</td><td>跨上下文/跨服务的通信方式</td></tr></tbody></table>',8)),(s(),l(i,null,{default:a(()=>[o(n,{id:"mermaid-204",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20%E6%A0%B8%E5%BF%83%E5%9F%9F%0A%20%20%20%20%20%20%20%20BC1%5B%E8%AE%A2%E5%8D%95%E4%B8%8A%E4%B8%8B%E6%96%87%3Cbr%2F%3EOrder%20Service%5D%0A%20%20%20%20%20%20%20%20BC2%5B%E6%94%AF%E4%BB%98%E4%B8%8A%E4%B8%8B%E6%96%87%3Cbr%2F%3EPayment%20Service%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E6%94%AF%E6%92%91%E5%9F%9F%0A%20%20%20%20%20%20%20%20BC3%5B%E7%89%A9%E6%B5%81%E4%B8%8A%E4%B8%8B%E6%96%87%3Cbr%2F%3ELogistics%20Service%5D%0A%20%20%20%20%20%20%20%20BC4%5B%E9%80%9A%E7%9F%A5%E4%B8%8A%E4%B8%8B%E6%96%87%3Cbr%2F%3ENotification%20Service%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E9%80%9A%E7%94%A8%E5%9F%9F%0A%20%20%20%20%20%20%20%20BC5%5B%E7%94%A8%E6%88%B7%E8%AE%A4%E8%AF%81%E4%B8%8A%E4%B8%8B%E6%96%87%3Cbr%2F%3EAuth%20Service%5D%0A%20%20%20%20end%0A%0A%20%20%20%20BC1%20--%3E%7C%22%E9%A2%86%E5%9F%9F%E4%BA%8B%E4%BB%B6%3Cbr%2F%3EOrderPlaced%22%7C%20BC2%0A%20%20%20%20BC2%20--%3E%7C%22%E9%A2%86%E5%9F%9F%E4%BA%8B%E4%BB%B6%3Cbr%2F%3EPaymentCompleted%22%7C%20BC3%0A%20%20%20%20BC2%20--%3E%7C%22%E9%A2%86%E5%9F%9F%E4%BA%8B%E4%BB%B6%3Cbr%2F%3EPaymentCompleted%22%7C%20BC4%0A%20%20%20%20BC1%20-.-%3E%7C%22%E5%85%B1%E4%BA%AB%E5%86%85%E6%A0%B8%3Cbr%2F%3EUser%20ID%22%7C%20BC5%0A%0A%20%20%20%20style%20BC1%20fill%3A%234d96ff%2Ccolor%3A%23fff%0A%20%20%20%20style%20BC2%20fill%3A%234d96ff%2Ccolor%3A%23fff%0A%20%20%20%20style%20BC3%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20BC4%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20BC5%20fill%3A%23ffd93d%2Ccolor%3A%23333%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[e(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=r(`<h3 id="_2-2-限界上下文的识别方法" tabindex="-1">2.2 限界上下文的识别方法 <a class="header-anchor" href="#_2-2-限界上下文的识别方法" aria-label="Permalink to &quot;2.2 限界上下文的识别方法&quot;">​</a></h3><p><strong>事件风暴（Event Storming）</strong> 是识别限界上下文最常用的工作坊方法：</p><ol><li><strong>识别领域事件</strong>：从业务流程出发，列举所有发生的事件（如&quot;订单已创建&quot;&quot;支付已完成&quot;）</li><li><strong>识别命令和聚合</strong>：找到触发事件的命令，围绕聚合根组织实体</li><li><strong>识别限界上下文</strong>：根据术语一致性和业务内聚性划分边界</li><li><strong>绘制上下文映射图</strong>：明确上下文之间的关系（上下游、共享内核、防腐层）</li></ol><div class="tip custom-block"><p class="custom-block-title">从事件风暴到微服务</p><p>事件风暴的输出天然适合指导微服务拆分。因为在风暴过程中，参与者已经在用业务语言而非技术语言思考边界——这与微服务&quot;围绕业务能力组织&quot;的理念完美契合。</p></div><hr><h2 id="三、三种拆分维度" tabindex="-1">三、三种拆分维度 <a class="header-anchor" href="#三、三种拆分维度" aria-label="Permalink to &quot;三、三种拆分维度&quot;">​</a></h2><h3 id="_3-1-按业务能力拆分-推荐" tabindex="-1">3.1 按业务能力拆分（推荐） <a class="header-anchor" href="#_3-1-按业务能力拆分-推荐" aria-label="Permalink to &quot;3.1 按业务能力拆分（推荐）&quot;">​</a></h3><p>最自然也是最常用的拆分方式，以电商系统为例：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>电商系统</span></span>
<span class="line"><span>├── 用户服务（User Service）        —— 注册、登录、个人信息</span></span>
<span class="line"><span>├── 商品服务（Product Service）      —— 商品管理、分类、SKU</span></span>
<span class="line"><span>├── 订单服务（Order Service）        —— 下单、订单状态、订单查询</span></span>
<span class="line"><span>├── 支付服务（Payment Service）      —— 支付、退款、对账</span></span>
<span class="line"><span>├── 库存服务（Inventory Service）    —— 库存扣减、库存预警</span></span>
<span class="line"><span>├── 物流服务（Logistics Service）    —— 发货、物流跟踪</span></span>
<span class="line"><span>└── 营销服务（Marketing Service）    —— 优惠券、促销活动</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>优点</strong>：业务边界清晰，与组织架构自然对齐，团队对服务有完整的掌控感。</p><h3 id="_3-2-按组织结构拆分-康威定律" tabindex="-1">3.2 按组织结构拆分（康威定律） <a class="header-anchor" href="#_3-2-按组织结构拆分-康威定律" aria-label="Permalink to &quot;3.2 按组织结构拆分（康威定律）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事业部结构 → 服务拆分</span></span>
<span class="line"><span></span></span>
<span class="line"><span>电商事业部 → 电商微服务集群</span></span>
<span class="line"><span>  ├── 订单团队 → 订单服务</span></span>
<span class="line"><span>  ├── 商品团队 → 商品服务</span></span>
<span class="line"><span>  └── 支付团队 → 支付服务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>金融事业部 → 金融微服务集群</span></span>
<span class="line"><span>  ├── 理财团队 → 理财服务</span></span>
<span class="line"><span>  └── 信贷团队 → 信贷服务</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">康威定律（Conway&#39;s Law）</p><blockquote><p>任何组织在设计系统时，其设计出的系统架构都将<strong>复制该组织的沟通结构</strong>。</p></blockquote><p>这意味着：如果你想让微服务拆得合理，<strong>先让团队结构合理</strong>。跨团队的微服务边界几乎必定出问题。</p></div><h3 id="_3-3-按变化频率拆分" tabindex="-1">3.3 按变化频率拆分 <a class="header-anchor" href="#_3-3-按变化频率拆分" aria-label="Permalink to &quot;3.3 按变化频率拆分&quot;">​</a></h3><p>这是最容易忽略但非常实用的维度：</p><table tabindex="0"><thead><tr><th>变化频率</th><th>适合的服务</th><th>特征</th></tr></thead><tbody><tr><td><strong>高频变化</strong></td><td>业务规则服务</td><td>促销引擎、风控规则、推荐算法 —— 频繁上线</td></tr><tr><td><strong>中频变化</strong></td><td>业务流程服务</td><td>订单流程、支付流程 —— 随业务迭代调整</td></tr><tr><td><strong>低频变化</strong></td><td>基础数据服务</td><td>用户、商品、字典 —— 结构稳定</td></tr><tr><td><strong>几乎不变</strong></td><td>基础设施服务</td><td>认证授权、网关、消息 —— 框架级稳定性</td></tr></tbody></table><p><strong>核心思想</strong>：将高频变化的模块与低频变化的模块分开部署。如果不分开，每次上线高频模块时都需要对稳定模块做全量回归，严重影响交付速度。</p><hr><h2 id="四、服务粒度判断" tabindex="-1">四、服务粒度判断 <a class="header-anchor" href="#四、服务粒度判断" aria-label="Permalink to &quot;四、服务粒度判断&quot;">​</a></h2><h3 id="_4-1-粒度过细-vs-粒度过粗" tabindex="-1">4.1 粒度过细 vs 粒度过粗 <a class="header-anchor" href="#_4-1-粒度过细-vs-粒度过粗" aria-label="Permalink to &quot;4.1 粒度过细 vs 粒度过粗&quot;">​</a></h3>`,20)),(s(),l(i,null,{default:a(()=>[o(n,{id:"mermaid-343",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20%E7%B2%92%E5%BA%A6%E8%BF%87%E7%BB%86%0A%20%20%20%20%20%20%20%20A1%5B%E8%AE%A2%E5%8D%95%E5%88%9B%E5%BB%BA%E6%9C%8D%E5%8A%A1%5D%0A%20%20%20%20%20%20%20%20A2%5B%E8%AE%A2%E5%8D%95%E6%9F%A5%E8%AF%A2%E6%9C%8D%E5%8A%A1%5D%0A%20%20%20%20%20%20%20%20A3%5B%E8%AE%A2%E5%8D%95%E5%8F%96%E6%B6%88%E6%9C%8D%E5%8A%A1%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E5%90%88%E7%90%86%E7%B2%92%E5%BA%A6%0A%20%20%20%20%20%20%20%20B1%5B%E8%AE%A2%E5%8D%95%E6%9C%8D%E5%8A%A1%3Cbr%2F%3E%E5%8C%85%E5%90%AB%E5%A2%9E%E5%88%A0%E6%94%B9%E6%9F%A5%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E7%B2%92%E5%BA%A6%E8%BF%87%E7%B2%97%0A%20%20%20%20%20%20%20%20C1%5B%E4%BA%A4%E6%98%93%E6%9C%8D%E5%8A%A1%3Cbr%2F%3E%E5%8C%85%E5%90%AB%E8%AE%A2%E5%8D%95%2B%E6%94%AF%E4%BB%98%2B%E7%89%A9%E6%B5%81%5D%0A%20%20%20%20end%0A%0A%20%20%20%20A1%20-.-%3E%7C%22%E5%90%88%E5%B9%B6%22%7C%20B1%0A%20%20%20%20A2%20-.-%3E%7C%22%E5%90%88%E5%B9%B6%22%7C%20B1%0A%20%20%20%20A3%20-.-%3E%7C%22%E5%90%88%E5%B9%B6%22%7C%20B1%0A%20%20%20%20C1%20-.-%3E%7C%22%E6%8B%86%E5%88%86%22%7C%20B1%0A%0A%20%20%20%20style%20A1%20fill%3A%23ff6b6b%2Ccolor%3A%23fff%0A%20%20%20%20style%20A2%20fill%3A%23ff6b6b%2Ccolor%3A%23fff%0A%20%20%20%20style%20A3%20fill%3A%23ff6b6b%2Ccolor%3A%23fff%0A%20%20%20%20style%20B1%20fill%3A%236bcb77%2Ccolor%3A%23fff%0A%20%20%20%20style%20C1%20fill%3A%23ff6b6b%2Ccolor%3A%23fff%0A"})]),fallback:a(()=>[...t[2]||(t[2]=[e(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=r('<h3 id="_4-2-粒度判断的-三个二-法则" tabindex="-1">4.2 粒度判断的&quot;三个二&quot;法则 <a class="header-anchor" href="#_4-2-粒度判断的-三个二-法则" aria-label="Permalink to &quot;4.2 粒度判断的&quot;三个二&quot;法则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>法则</th><th>说明</th></tr></thead><tbody><tr><td><strong>2 Pizza Team</strong></td><td>一个服务由一个 6-8 人的团队负责，不多不少</td></tr><tr><td><strong>2 周迭代</strong></td><td>一个服务的一个功能迭代应该能在 2 周内完成</td></tr><tr><td><strong>2 个数据库表簇</strong></td><td>一个服务通常管理 2-5 个核心聚合，每个聚合对应 1-3 张表</td></tr></tbody></table><h3 id="_4-3-粒度判断信号" tabindex="-1">4.3 粒度判断信号 <a class="header-anchor" href="#_4-3-粒度判断信号" aria-label="Permalink to &quot;4.3 粒度判断信号&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">粒度太细的信号（纳米服务反模式）</p><ul><li>服务间需要频繁的同步调用才能完成一个业务操作</li><li>修改一个功能需要同时修改和部署 3 个以上服务</li><li>服务间的 RPC 延迟超过了业务处理时间</li><li>每个服务只管理 1-2 张表</li></ul></div><div class="warning custom-block"><p class="custom-block-title">粒度太粗的信号（迷你单体反模式）</p><ul><li>不同团队频繁修改同一个服务的同一块代码</li><li>服务部署时需要跑 30 分钟以上的全量回归测试</li><li>服务内部模块之间的调用比服务间调用还多</li><li>你很难说清楚这个服务&quot;到底做什么&quot;</li></ul></div><hr><h2 id="五、常见拆分反模式" tabindex="-1">五、常见拆分反模式 <a class="header-anchor" href="#五、常见拆分反模式" aria-label="Permalink to &quot;五、常见拆分反模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>反模式</th><th>描述</th><th>为什么危险</th><th>正确做法</th></tr></thead><tbody><tr><td><strong>按技术层拆分</strong></td><td>Controller 一个服务、Service 一个服务、DAO 一个服务</td><td>跨层调用极其频繁，延迟爆炸，改了业务逻辑要部署全部三层</td><td>按业务能力垂直拆分</td></tr><tr><td><strong>按数据库表拆分</strong></td><td>每张表一个服务</td><td>跨表 JOIN 变成网络调用，性能和一致性都是灾难</td><td>按聚合边界拆分</td></tr><tr><td><strong>过早拆分</strong></td><td>业务尚不确定时就按预设架构拆分</td><td>边界画错重来的成本很高，过早优化是万恶之源</td><td>先单体验证业务，后逐步拆分</td></tr><tr><td><strong>大爆炸重写</strong></td><td>停掉老系统，花 6 个月从零写微服务</td><td>风险极高，上线即事故</td><td>绞杀者模式逐步迁移</td></tr><tr><td><strong>数据大杂烩</strong></td><td>多个服务共享数据库</td><td>本质上还是分布式单体，无法独立演进</td><td>每个服务独占数据库</td></tr></tbody></table><hr><h2 id="⭐-面试高频问题汇总" tabindex="-1">⭐ 面试高频问题汇总 <a class="header-anchor" href="#⭐-面试高频问题汇总" aria-label="Permalink to &quot;⭐ 面试高频问题汇总&quot;">​</a></h2><h3 id="q1-如何确定微服务的合适粒度-有没有客观的度量标准" tabindex="-1">Q1：如何确定微服务的合适粒度？有没有客观的度量标准？ <a class="header-anchor" href="#q1-如何确定微服务的合适粒度-有没有客观的度量标准" aria-label="Permalink to &quot;Q1：如何确定微服务的合适粒度？有没有客观的度量标准？&quot;">​</a></h3><p>没有绝对的量化标准，但可以通过以下维度综合判断：</p><ol><li><strong>团队维度</strong>：一个服务由一个 2 Pizza Team（6-8 人）负责</li><li><strong>业务维度</strong>：一个服务对应一个业务能力，可以独立交付价值</li><li><strong>数据维度</strong>：一个服务管理 2-5 个核心聚合，不跨聚合做强一致性事务</li><li><strong>通信维度</strong>：一次业务操作不需要超过 3 次跨服务同步调用</li><li><strong>部署维度</strong>：一个服务可以独立测试、独立部署、独立扩缩容</li></ol><p>关键原则：<strong>先粗后细</strong>。服务粒度可以在演进中调整，拆太细再合并的成本远高于从粗到细逐步优化。</p><h3 id="q2-ddd-的限界上下文和微服务是什么关系" tabindex="-1">Q2：DDD 的限界上下文和微服务是什么关系？ <a class="header-anchor" href="#q2-ddd-的限界上下文和微服务是什么关系" aria-label="Permalink to &quot;Q2：DDD 的限界上下文和微服务是什么关系？&quot;">​</a></h3><p>限界上下文是 DDD 战略设计的核心概念，它定义了一个<strong>业务边界</strong>——在这个边界内，业务术语的含义是统一的。微服务的服务边界理想情况应该对齐限界上下文：</p><ul><li><strong>一对一映射</strong>（理想）：一个限界上下文 = 一个微服务</li><li><strong>一对多映射</strong>（常见）：一个限界上下文包含多个微服务（当上下文内部模块较复杂时）</li><li><strong>不映射</strong>（反模式）：一个微服务跨越多个限界上下文，意味着出现了边界混乱</li></ul><p>关键是理解：限界上下文是<strong>逻辑边界</strong>，微服务是<strong>物理边界</strong>。先用 DDD 确定逻辑边界，再映射为物理边界。</p><h3 id="q3-有哪些明确的信号说明服务应该拆分" tabindex="-1">Q3：有哪些明确的信号说明服务应该拆分？ <a class="header-anchor" href="#q3-有哪些明确的信号说明服务应该拆分" aria-label="Permalink to &quot;Q3：有哪些明确的信号说明服务应该拆分？&quot;">​</a></h3><ol><li><strong>不同模块的变更节奏差异大</strong>：核心支付模块一年改 2 次，营销模块一天上线 3 次——它们不应该在一个服务里</li><li><strong>不同模块的扩容需求差异大</strong>：商品浏览 QPS 是下单 QPS 的 100 倍，需要独立扩容</li><li><strong>不同团队在争夺同一服务的修改权</strong>：频繁的代码冲突和上线协调</li><li><strong>数据库表之间越来越独立</strong>：某几张表和其余表的关联越来越少</li><li><strong>测试范围过大</strong>：改一个功能需要回归测试全服务，测试时间越来越长</li></ol><h3 id="q4-什么是-按技术层拆分-为什么这是反模式" tabindex="-1">Q4：什么是&quot;按技术层拆分&quot;？为什么这是反模式？ <a class="header-anchor" href="#q4-什么是-按技术层拆分-为什么这是反模式" aria-label="Permalink to &quot;Q4：什么是&quot;按技术层拆分&quot;？为什么这是反模式？&quot;">​</a></h3><p>按技术层拆分就是把 MVC 三层分别部署为独立服务：Controller 微服务 → Service 微服务 → DAO 微服务。</p><p><strong>为什么是反模式</strong>：</p><ol><li>一个业务请求需要穿透三层服务，增加 2 次网络跳转，延迟大幅增加</li><li>三层之间耦合极其紧密，改了业务逻辑通常要同时部署三层</li><li>任何一层挂了，整个业务链路不可用</li></ol><p>正确的做法是<strong>垂直拆分</strong>：每个服务包含完整的表现层、业务层、数据访问层，自给自足。</p><h3 id="q5-如果已经拆错了-服务粒度太细-如何合并" tabindex="-1">Q5：如果已经拆错了，服务粒度太细，如何合并？ <a class="header-anchor" href="#q5-如果已经拆错了-服务粒度太细-如何合并" aria-label="Permalink to &quot;Q5：如果已经拆错了，服务粒度太细，如何合并？&quot;">​</a></h3><ol><li><strong>识别合并目标</strong>：选择调用最频繁、数据耦合最紧密的一组服务</li><li><strong>统一数据源</strong>：先将多个数据库合并（这是最难的一步，注意数据冲突和迁移方案）</li><li><strong>代码合并</strong>：将多个服务的代码合并到一个代码仓库</li><li><strong>渐进切换</strong>：保持旧服务运行，逐步将流量切到新合并的服务</li><li><strong>下线旧服务</strong>：确认无流量后再下线</li></ol><p>关键原则：<strong>数据库合并是最危险的一步</strong>，必须做好数据校验和回滚方案。</p><h3 id="q6-微服务拆分和康威定律的关系" tabindex="-1">Q6：微服务拆分和康威定律的关系？ <a class="header-anchor" href="#q6-微服务拆分和康威定律的关系" aria-label="Permalink to &quot;Q6：微服务拆分和康威定律的关系？&quot;">​</a></h3><p>康威定律的核心观点：系统架构反映了组织的沟通结构。在微服务拆分中的实践含义：</p><ul><li><strong>反向康威</strong>：如果你想得到某种架构，先调整组织结构。比如想拆分订单和支付，就让两个团队分别负责</li><li><strong>跨团队服务集成必定困难</strong>：因为两个团队的沟通成本天然高于一个团队内部。所以服务边界应该沿着团队边界画</li><li><strong>避免一个服务由多个团队维护</strong>：这会导致代码所有权模糊、决策成本高</li></ul><hr><div class="info custom-block"><p class="custom-block-title">相关模块</p><ul><li><a href="./">微服务架构全景</a> — 架构演进与适用场景</li><li><a href="./../spring-cloud/">Spring Cloud 技术实现</a> — Nacos、Gateway、Sentinel、Seata 等</li><li>分布式理论（middleware/distributed-system/） — 分布式事务、一致性协议</li></ul></div>',33))])}const m=d(p,[["render",c]]);export{f as __pageData,m as default};
